export interface AppDefinition {
  id: string; // GUID
  name: string;
  description: string;
  shortDescription: string;
  iconUrl: string;
  userId: string; // Organization ID or User ID
  developerName: string;
  status:
    | 'draft'
    | 'pendingReview'
    | 'approved'
    | 'rejected'
    | 'suspended'
    | 'underReview'
    | 'changesRequested'
    | 'withdrawn';

  // Integration Configuration
  integrationPoints: IntegrationPoint[];
  endpoint: {
    baseUrl: string; // The root URL of the widget
    healthCheckUrl?: string;
  };

  // Store Metadata
  pricing: {
    model: 'FREE' | 'SUBSCRIPTION' | 'ONE_TIME';
    price: number;
    currency: string;
    trialDays?: number;
  };
  categories: string[];
  tags: string[];

  // Stats (Computed/Cached)
  averageRating: number; // 0-5
  reviewCount: number;
  installCount: number;
  updatedAt: string; // ISO Date
  createdAt: string; // ISO Date
}

export interface IntegrationPoint {
  screenId: 'TRIP_DETAILS' | 'VEHICLE_ACTIVITY' | 'DASHBOARD' | 'REPORTS';
  widgetSize: 'MEDIUM' | 'FULL_WIDTH' | 'CARD';
  requiredPermissions: string[]; // e.g., ['READ_VEHICLE', 'READ_TRIPS']
}

export interface AppReview {
  id: string;
  appId: string;
  userId: string;
  userName: string;
  organizationName: string;
  rating: number; // 1-5
  title: string;
  comment: string;
  developerResponse?: string; // Optional reply from dev
  isVerifiedPurchase: boolean;

  // Community Feedback
  helpfulCount: number; // Number of users who clicked "Was this helpful?"

  createdAt: string;
}

